  1	import React from 'react';
  2	
  3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  4	import {
  5	  Button,
  6	  ButtonVariant,
  7	  Popover,
  8	  PopoverPosition,
  9	  Progress,
 10	  Spinner,
 11	  Stack,
 12	  StackItem,
 13	} from '@patternfly/react-core';
 14	import { BanIcon, ErrorCircleOIcon, InProgressIcon } from '@patternfly/react-icons';
 15	import { t_global_color_status_danger_default as dangerColor } from '@patternfly/react-tokens/dist/js/t_global_color_status_danger_default';
 16	
 17	import { UPLOAD_STATUS } from '../utils/consts';
 18	import { DataUpload } from '../utils/types';
 19	import { getProgressVariant } from '../utils/utils';
 20	
 21	type UploadPVCPopoverUploadStatusProps = {
 22	  error: { message: string };
 23	  onCancelClick: () => void;
 24	  onErrorDeleteSource: () => void;
 25	  upload: DataUpload;
 26	};
 27	
 28	const UploadPVCPopoverUploadStatus: React.FC<UploadPVCPopoverUploadStatusProps> = ({
 29	  error,
 30	  onCancelClick,
 31	  onErrorDeleteSource,
 32	  upload,
 33	}) => {
 34	  const { t } = useKubevirtTranslation();
 35	
 36	  const getPopoverBody = (status: string) => {
 37	    switch (status) {
 38	      case UPLOAD_STATUS.ERROR:
 39	        return {
 40	          body: error?.message,
 41	          icon: <ErrorCircleOIcon className="co-icon-and-text__icon" color={dangerColor?.value} />,
 42	          title: t('Upload error'),
 43	        };
 44	      case UPLOAD_STATUS.CANCELED:
 45	        return {
 46	          body: error ? error?.message : t('Removing Resources'),
 47	          icon: (
 48	            <BanIcon className="co-icon-and-text__icon" color={error ? dangerColor?.value : ''} />
 49	          ),
 50	          title: error ? t('Cancel error') : t('Upload canceled'),
 51	        };
 52	      case UPLOAD_STATUS.UPLOADING:
 53	        return {
 54	          body: t('Please do not close this window, you can keep navigating the app freely.'),
 55	          icon: <InProgressIcon className="co-icon-and-text__icon" />,
 56	          title: t('Uploading'),
 57	        };
 58	      case UPLOAD_STATUS.SUCCESS:
 59	        return {
 60	          icon: <InProgressIcon className="co-icon-and-text__icon" />,
 61	          title: t('Upload finished'),
 62	        };
 63	      default:
 64	        return null;
 65	    }
 66	  };
 67	
 68	  const uploadPopoverBody = getPopoverBody(upload?.uploadStatus);
 69	  return (
 70	    <Popover
 71	      bodyContent={
 72	        <Stack hasGutter>
 73	          <StackItem>
 74	            {upload?.uploadStatus === UPLOAD_STATUS.CANCELED && (
 75	              <Spinner className="co-icon-and-text__icon" size="md" />
 76	            )}
 77	            {uploadPopoverBody?.body}
 78	          </StackItem>
 79	          <StackItem>
 80	            <Progress
 81	              title={upload?.fileName}
 82	              value={upload?.progress}
 83	              variant={getProgressVariant(upload?.uploadStatus)}
 84	            />
 85	          </StackItem>
 86	          {upload?.uploadStatus === UPLOAD_STATUS.UPLOADING && (
 87	            <StackItem>
 88	              <Button
 89	                className="pf-m-link--align-left"
 90	                id="cdi-upload-cancel-btn"
 91	                onMouseUp={onCancelClick}
 92	                variant="link"
 93	              >
 94	                {t('Cancel upload')}
 95	              </Button>
 96	            </StackItem>
 97	          )}
 98	          {upload?.uploadStatus === UPLOAD_STATUS.ERROR && (
 99	            <StackItem>
100	              <Button
101	                className="pf-m-link--align-left"
102	                id="cdi-upload-delete-btn"
103	                isDanger
104	                onMouseUp={onErrorDeleteSource}
105	                variant="link"
106	              >
107	                {t('Delete source')}
108	              </Button>
109	            </StackItem>
110	          )}
111	        </Stack>
112	      }
113	      headerContent={<div>{uploadPopoverBody?.title}</div>}
114	      position={PopoverPosition.bottom}
115	    >
116	      <Button
117	        className="pf-m-link--align-left"
118	        id="cdi-upload-popover-btn"
119	        variant={ButtonVariant.link}
120	      >
121	        {uploadPopoverBody?.icon}
122	        {uploadPopoverBody?.title}
123	      </Button>
124	    </Popover>
125	  );
126	};
127	
128	export default UploadPVCPopoverUploadStatus;

